    "print(\"✓ Generating Pairplot (Target vs Key Features)...\")\n",
    "sns.pairplot(df[num_cols], diag_kind='kde', plot_kws={'alpha': 0.5})\n",
    "plt.suptitle('Variable Relationships & Distributions (Pairplot)', y=1.02, fontsize=16, fontweight='bold')\n",
    "plt.show()\n",
