    "ax3.text(0.5, 0.2, 'Features', ha='center', va='center', fontsize=14, fontweight='bold')\n",
    "ax3.set_xlim(0, 1)\n",
    "ax3.set_ylim(0, 1)\n",
    "ax3.axis('off')\n",
    "ax3.set_title('Feature Dimension', fontweight='bold', fontsize=12)\n",
    "\n",
    "# Before scaling distribution\n",
    "ax4 = fig.add_subplot(gs[1, 0:2])\n",
