    "colors = ['#FF6B6B', '#4ECDC4', '#45B7D1', '#FFA07A']\n",
    "\n",
    "# 1. R² Comparison\n",
    "ax1 = fig.add_subplot(gs[0, 0])\n",
    "bars1 = ax1.bar(['LR', 'Ridge', 'GB', 'RF'], results_df['Test R²'].values, \n",
