    "             ha='center', va='bottom', fontweight='bold', fontsize=10)\n",
    "\n",
    "# 2. RMSE Comparison\n",
    "ax2 = fig.add_subplot(gs[0, 1])\n",
    "bars2 = ax2.bar(['LR', 'Ridge', 'GB', 'RF'], results_df['RMSE'].values, \n",
