    "ax2.set_ylabel('RMSE (RM)', fontweight='bold', fontsize=11)\n",
    "ax2.set_title('RMSE Comparison', fontweight='bold', fontsize=12)\n",
    "ax2.grid(axis='y', alpha=0.3)\n",
    "for bar, val in zip(bars2, results_df['RMSE'].values):\n",
