    "y_pred_ridge = np.expm1(ridge_search.best_estimator_.predict(X_test))\n",
    "\n",
    "# 2. Now your dictionary will find 'y_pred_gb' without crashing\n",
    "best_preds_dict = {\n",
    "    'Linear Regression': y_pred_lr,\n",
    "    'Ridge Regression': y_pred_ridge,\n",
